def test_create_encounter_valid_timestamps(clinician_client, existing_patient_id):
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {
            "start": "2024-06-01T08:00:00Z",
            "end":   "2024-06-01T09:00:00Z"
        }
    }
    resp = clinician_client.post("/Encounter", json=payload)
    assert resp.status_code == 201
    body = resp.json()
    assert "id" in body
    assert body["period"]["start"] == payload["period"]["start"]
    assert body["period"]["end"]   == payload["period"]["end"]

