def test_create_encounter_end_equals_start_boundary(clinician_client, existing_patient_id):
    ts = "2024-06-01T08:00:00Z"
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {"start": ts, "end": ts}
    }
    resp = clinician_client.post("/Encounter", json=payload)
    assert resp.status_code in (201, 422), (
        f"Unexpected status {resp.status_code} for zero-duration encounter"
    )
    # determinism check: second identical call must return same status class
    resp2 = clinician_client.post("/Encounter", json=payload)
    assert resp2.status_code == resp.status_code or resp2.status_code == 201

