def test_create_encounter_duplicate_active_state_transition(clinician_client, existing_patient_id):
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "subject": {"reference": f"Patient/{existing_patient_id}"},
        "period": {"start": "2024-06-01T08:00:00Z", "end": "2024-06-01T09:00:00Z"}
    }
    first = clinician_client.post("/Encounter", json=payload)
    assert first.status_code == 201, "Setup: first encounter must be created"

    second = clinician_client.post("/Encounter", json=payload)
    assert second.status_code in (409, 422), (
        f"Conflicting active encounter should be rejected, got {second.status_code}"
    )
    <cleanup_encounter>(clinician_client, first.json()["id"])
